// Unit 13. Les pronoms
// Object Pronouns, Y & En

export default {n:13,lang:"fr",srcLang:"en",track:"v2",title:"Les pronoms",sub:"Object Pronouns, Y & En",icon:"🔀",level:"A2.5",color:"#7B5EE8",lessons:[
  {id:"fre13l1",title:"Les pronoms COD",icon:"🎯",xp:15,board:true,steps:[
        {type:"intro",title:"Direct object pronouns",desc:"Direct object pronouns replace the thing or person receiving the action directly. Instead of repeating the noun, French uses le, la, les, me, te, nous, vous.",goals:["Understand what a direct object is","Learn the COD pronouns","Place them before the verb"]},
        {type:"tip",title:"COD pronouns",text:"COD = complément d'objet direct\n\nme (m') = me\nte (t') = you\nle (l') = him/it (masc.)\nla (l') = her/it (fem.)\nnous = us\nvous = you (pl./formal)\nles = them\n\nPlacement: BEFORE the conjugated verb.\nTu manges la pomme. -> Tu la manges.\nJe vois Pierre. -> Je le vois.\n\nBefore vowels: le/la become l'.\nJe l'aime. (I love him/her.)"},
        {type:"teach",trg:"le",src:"him / it (masculine)",pos:"intj",gender:null,phonetic:"luh",note:"Le replaces a masculine noun.\nTu vois le chat -> Tu le vois.\nPlaced BEFORE the verb.",example:"A: Tu vois le chat?\nB: Oui, je le vois!\nA: Il est mignon, non?",exampleSrc:"A: Do you see the cat?\nB: Yes, I see it!\nA: It's cute, right?",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"la",src:"her / it (feminine)",pos:"noun",gender:"f",phonetic:"lah",note:"La replaces a feminine noun.\nTu connais la chanson -> Tu la connais.\nBefore a vowel: la becomes l'.",example:"A: Tu connais cette chanson?\nB: Oui, je la connais bien!\nA: C'est ma préférée aussi.",exampleSrc:"A: Do you know this song?\nB: Yes, I know it well!\nA: It's my favorite too.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"les",src:"them",pos:"noun",gender:"m",phonetic:"lay",note:"Les replaces any plural noun.\nTu vois les enfants -> Tu les vois.\nSame form for masculine and feminine.",example:"A: Tu as vu mes clés?\nB: Oui, je les ai vues sur la table.\nA: Merci!",exampleSrc:"A: Have you seen my keys?\nB: Yes, I saw them on the table.\nA: Thanks!",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"mc",q:"Pizza is feminine in French. In 'Oui, je ___ mange', which pronoun fits?",opts:["la","le","les","lui"],ans:"la",hint:"The direct object pronoun must match the gender of the noun it substitutes."},
        {type:"fb",opts:["le","la","les","lui"],hint:"I see him every day. Masculine singular direct object.",s:"Je {1} vois tous les jours. (him)",a:"le"},
        {type:"mc",q:"Where does the COD pronoun go?",opts:["After the verb","Before the conjugated verb","At the end of the sentence","Before the subject"],ans:"Before the conjugated verb",hint:"Je la mange, tu le vois, nous les aimons."},
        {type:"fb",opts:["la","le","les","lui"],hint:"Do you know her? Feminine singular direct object.",s:"Tu {1} connais? (her)",a:"la"},
        {type:"match",pairs:[{trg:"le",src:"him/it (masc.)"},{trg:"la",src:"her/it (fem.)"},{trg:"les",src:"them"},{trg:"l'",src:"him/her (before vowel)"}]},
        {type:"mc",q:"'J'aime Marie.' -> 'Je ___.'",opts:["lui aime","la aime","l'aime","les aime"],ans:"l'aime",hint:"When the verb starts with a vowel, the pronoun contracts."},
        {type:"fb",opts:["le","la","les","lui"],hint:"We're watching it tonight. Le film = masculine.",s:"Nous {1} regardons ce soir. (the film, masc.)",a:"le"},
        {type:"mc",q:"Croissants are plural. In 'Oui, je ___ achète', which pronoun fits?",opts:["le","la","lui","les"],ans:"les",hint:"The pronoun must match the number of the noun being substituted."},
        {type:"fb",opts:["nous","vous","les","leur"],hint:"She's inviting us to the party.",s:"Elle {1} invite à la fête. (us)",a:"nous"},
        {type:"match",pairs:[{trg:"me",src:"me"},{trg:"te",src:"you"},{trg:"nous",src:"us"},{trg:"vous",src:"you (pl./formal)"}]},
        {type:"mc",q:"In the negative: 'Je ne ___ vois pas.' (him)",opts:["le","la","les","lui"],ans:"le",hint:"Ne + pronoun + verb + pas. The pronoun stays before the verb."},
        {type:"fb",opts:["les","le","la","leur"],hint:"He doesn't understand them. Pronoun between ne and the verb.",s:"Il ne {1} comprend pas. (them)",a:"les"},
        {type:"mc",q:"In passé composé: 'Je l'ai vu.' The pronoun goes before:",opts:["The past participle","The auxiliary (avoir/être)","The subject","The end"],ans:"The auxiliary (avoir/être)",hint:"Je l'ai vu. The pronoun goes before ai, not before vu."}
  ]},
  {id:"fre13l2",title:"Les pronoms COI",icon:"📨",xp:15,board:true,steps:[
        {type:"intro",title:"Indirect object pronouns",desc:"Indirect object pronouns replace the person TO WHOM or FOR WHOM something is done. French uses me, te, lui, nous, vous, leur. They replace 'à + person'.",goals:["Distinguish direct from indirect objects","Learn COI pronouns","Use lui and leur correctly"]},
        {type:"tip",title:"COI pronouns",text:"COI = complément d'objet indirect\nReplace: à + person\n\nme (m') = to me\nte (t') = to you\nlui = to him / to her\nnous = to us\nvous = to you (pl./formal)\nleur = to them\n\nJe parle à Pierre. -> Je lui parle.\nJ'écris à mes parents. -> Je leur écris.\n\nNOTE: lui = to him OR to her!\nleur = to them (no -s, never leurs)"},
        {type:"teach",trg:"lui",src:"to him / to her",pos:"verb",gender:null,phonetic:"lwee",note:"Lui = to him OR to her.\nReplaces à + person (singular).\nJe parle à Marie -> Je lui parle.",example:"A: Tu parles à Marie?\nB: Oui, je lui parle souvent.\nA: Tu lui dis bonjour de ma part!",exampleSrc:"A: Do you talk to Marie?\nB: Yes, I often talk to her.\nA: Say hello to her from me!",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"leur",src:"to them",pos:"verb",gender:null,phonetic:"luhr",note:"Leur = to them (plural).\nNever add -s (not 'leurs').\nJ'écris à mes amis -> Je leur écris.",example:"A: Tu téléphones à tes parents?\nB: Oui, je leur téléphone chaque semaine.\nA: C'est bien!",exampleSrc:"A: Do you call your parents?\nB: Yes, I call them every week.\nA: That's good!",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"'Je parle à Marc.' -> 'Je ___ parle.'",opts:["lui","la","le","leur"],ans:"lui",hint:"Parler à + person = indirect. Singular = which pronoun?"},
        {type:"fb",opts:["lui","leur","le","la"],hint:"She sent a message to him. A + person = indirect.",s:"Elle {1} a envoyé un message. (to him)",a:"lui"},
        {type:"mc",q:"How do you say 'I write to them'?",opts:["Je les écris","Je leur écris","Je leurs écris","Je lui écris"],ans:"Je leur écris",hint:"To them = indirect plural. Never add -s to this pronoun."},
        {type:"fb",opts:["lui","leur","la","le"],hint:"We give the gift to her. To + person = indirect.",s:"Nous {1} donnons le cadeau. (to her)",a:"lui"},
        {type:"match",pairs:[{trg:"lui (singular)",src:"to him / to her"},{trg:"leur (plural)",src:"to them"},{trg:"me",src:"to me"},{trg:"te",src:"to you"}]},
        {type:"mc",q:"'Je ___ téléphone.' (to my parents)",opts:["Les","Leurs","Leur","Lui"],ans:"Leur",hint:"To my parents (plural) = which indirect pronoun?"},
        {type:"fb",opts:["lui","leur","la","le"],hint:"Did you ask her? Demander à = takes indirect object.",s:"Tu {1} as demandé? (to her)",a:"lui"},
        {type:"tip",title:"COD vs COI: how to tell",text:"COD answers: WHAT? / WHOM? (no preposition)\nJe vois Marie. (I see WHOM? Marie.)\n-> Je la vois.\n\nCOI answers: TO WHOM? (à + person)\nJe parle à Marie. (I speak TO WHOM? To Marie.)\n-> Je lui parle.\n\nCommon COI verbs:\nparler à, téléphoner à, écrire à,\ndonner à, dire à, demander à,\nrépondre à, envoyer à, montrer à"},
        {type:"mc",q:"'Je vois Pierre' uses COD. 'Je parle à Pierre' uses COI. Why?",opts:["Both are direct","It depends on the time","Both use 'à'","Vois has no preposition, parle has 'à'"],ans:"Vois has no preposition, parle has 'à'",hint:"Direct = no ___. Indirect = à before the person."},
        {type:"fb",opts:["leur","lui","les","la"],hint:"I told them the truth. Dire à = indirect object.",s:"Je {1} ai dit la vérité. (to them)",a:"leur"},
        {type:"match",pairs:[{trg:"Je le vois",src:"I see HIM (COD)"},{trg:"Je lui parle",src:"I speak TO HIM (COI)"},{trg:"Je les invite",src:"I invite THEM (COD)"},{trg:"Je leur écris",src:"I write TO THEM (COI)"}]},
        {type:"mc",q:"'Elle montre la photo à ses amis.' Replace 'à ses amis':",opts:["Elle leur montre la photo","Elle les montre la photo","Elle lui montre la photo","Elle la montre ses amis"],ans:"Elle leur montre la photo",hint:"To her friends (plural) = which indirect pronoun?"},
        {type:"fb",opts:["me","lui","le","leur"],hint:"He always answers me quickly. Répondre à = indirect.",s:"Il {1} répond toujours vite. (to me)",a:"me"},
        {type:"mc",q:"In 'Je lui donne le livre', 'lui' could mean:",opts:["Only 'to him'","Either 'to him' or 'to her'","Only 'to her'","'to them'"],ans:"Either 'to him' or 'to her'",hint:"This pronoun is gender-neutral for indirect singular."}
  ]},
  {id:"fre13l3",title:"Le pronom Y",icon:"📍",xp:15,board:true,steps:[
        {type:"intro",title:"The pronoun Y",desc:"Y replaces 'à + place' or 'à + thing' (not a person). It usually means 'there' or 'to it'. It's one of the most common words in spoken French.",goals:["Understand what Y replaces","Use Y for places","Use Y with expressions"]},
        {type:"tip",title:"Y = there / to it",text:"Y replaces:\n1. à + PLACE: J'habite à Paris. -> J'y habite.\n2. à + THING: Je pense à mon travail. -> J'y pense.\n3. Other prepositions of place:\n   dans, sur, chez, en + place -> y\n\nPlacement: BEFORE the conjugated verb.\nTu vas au cinéma? -> Tu y vas?\n\nNOTE: Y never replaces à + PERSON.\nJe pense à Marie -> Je pense à elle (not j'y pense)."},
        {type:"teach",trg:"y",src:"there / to it",pos:"verb",gender:null,phonetic:"ee",note:"Y replaces the place.\nTu vas au supermarché -> Tu y vas.\nPlaced before the conjugated verb.",example:"A: Tu vas au supermarché?\nB: Oui, j'y vais maintenant.\nA: Tu peux acheter du lait?",exampleSrc:"A: Are you going to the supermarket?\nB: Yes, I'm going there now.\nA: Can you buy some milk?",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"J'y suis, j'y reste.",src:"I'm here, I'm staying here.",pos:"intj",gender:null,phonetic:"zhee SWEE zhee REST",note:"Famous French expression.\nBoth y = in this place.\nMeaning: I'm not going anywhere!",example:"A: Tu ne veux pas déménager?\nB: Non! J'y suis, j'y reste!\nA: Tu aimes vraiment cette ville!",exampleSrc:"A: Don't you want to move?\nB: No! I'm here, I'm staying here!\nA: You really love this city!",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"mc",q:"Replacing a location with a pronoun: 'Oui, j'___ habite.' Which fits?",opts:["y","en","le","la"],ans:"y",hint:"This pronoun replaces à + place expressions like city names."},
        {type:"fb",opts:["y","en","le","la"],hint:"We're going there tomorrow. Place pronoun.",s:"Nous {1} allons demain. (to the beach)",a:"y"},
        {type:"mc",q:"'Elle pense à son travail.' -> 'Elle ___ pense.'",opts:["En","Y","Le","La"],ans:"Y",hint:"Replacing à + thing (not a person). Which pronoun?"},
        {type:"fb",opts:["y","en","le","la"],hint:"Did you go there yesterday? Place replacement.",s:"Tu {1} es allé hier? (to the cinema)",a:"y"},
        {type:"match",pairs:[{trg:"à Paris -> y",src:"there (place)"},{trg:"au bureau -> y",src:"there (place)"},{trg:"à mon travail -> y",src:"to it (thing)"},{trg:"dans le jardin -> y",src:"there (place)"}]},
        {type:"mc",q:"Y can NOT replace:",opts:["à + place","à + thing","à + person","dans + place"],ans:"à + person",hint:"For people, use lui/leur or stressed pronouns (à elle, à eux)."},
        {type:"fb",opts:["y","en","lui","la"],hint:"I think about it often. A + thing = which pronoun?",s:"J'{1} pense souvent. (to my vacation)",a:"y"},
        {type:"mc",q:"'Il y a du lait?' What does 'y' represent here?",opts:["A specific place","A thing","A person","It's part of a fixed expression"],ans:"It's part of a fixed expression",hint:"Il y a = there is/are. A ___ ___ where y has no separate meaning."},
        {type:"fb",opts:["y","en","les","le"],hint:"The children play there every day. Place pronoun.",s:"Les enfants {1} jouent tous les jours. (in the park)",a:"y"},
        {type:"match",pairs:[{trg:"Je vais au café",src:"J'y vais"},{trg:"Tu restes chez toi",src:"Tu y restes"},{trg:"Elle travaille en France",src:"Elle y travaille"},{trg:"Nous pensons à ça",src:"Nous y pensons"}]},
        {type:"mc",q:"In passé composé: 'J'y suis allé.' Y goes before:",opts:["The auxiliary verb","The past participle","The subject","The end"],ans:"The auxiliary verb",hint:"Same rule as COD/COI: pronoun before the conjugated ___."},
        {type:"fb",opts:["y","en","le","la"],hint:"Have you been there already? Place replacement.",s:"Vous {1} êtes déjà allés? (to this restaurant)",a:"y"},
        {type:"mc",q:"'On y va!' is a common expression meaning:",opts:["We leave it","Let's go!","We see it","It's there"],ans:"Let's go!",hint:"Literally: one goes there. An everyday way to rally the group."},
        {type:"fb",opts:["y","en","le","la"],hint:"I don't understand anything about it. A + abstract thing.",s:"Je ne {1} comprends rien. (to this problem)",a:"y"}
  ]},
  {id:"fre13l4",title:"Le pronom en",icon:"🧩",xp:15,board:true,steps:[
        {type:"intro",title:"The pronoun EN",desc:"En replaces 'de + something' or a quantity expression. It usually means 'of it', 'some', or 'any'. Essential for talking about quantities.",goals:["Understand what EN replaces","Use EN for quantities","Use EN with de + noun expressions"]},
        {type:"tip",title:"En = of it / some",text:"EN replaces:\n1. du/de la/des + noun (partitive):\nTu veux du café? -> Tu en veux?\n\n2. de + noun (after expressions):\nJ'ai besoin de repos. -> J'en ai besoin.\n\n3. Number/quantity + noun:\nJ'ai trois chats. -> J'en ai trois.\n(Keep the number, replace the noun!)\n\n4. Expressions with de:\navoir besoin de, avoir peur de,\nparler de, venir de\n\nPlacement: BEFORE the conjugated verb."},
        {type:"teach",trg:"en",src:"of it / some / any",pos:"verb",gender:null,phonetic:"ahn",note:"En replaces du/de la/des + noun.\nDu chocolat -> en.\nPlaced before the verb.",example:"A: Tu veux du chocolat?\nB: Oui, j'en veux bien!\nA: Il y en a dans le placard.",exampleSrc:"A: Do you want some chocolate?\nB: Yes, I'd like some!\nA: There's some in the cupboard.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"J'en ai trois.",src:"I have three (of them).",pos:"noun",gender:null,phonetic:"zhahn ay TRWAH",note:"With quantities, keep the number.\nJ'ai trois chats -> J'en ai trois.\nThe noun disappears, the number stays.",example:"A: Tu as des frères et soeurs?\nB: J'en ai trois: deux frères et une soeur.\nA: C'est une grande famille!",exampleSrc:"A: Do you have brothers and sisters?\nB: I have three: two brothers and one sister.\nA: It's a big family!",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"mc",q:"'Tu veux du café?' -> 'Oui, j'___ veux.'",opts:["en","y","le","la"],ans:"en",hint:"Du + noun (partitive) = which pronoun replaces it?"},
        {type:"fb",opts:["en","y","les","le"],hint:"I bought two of them. Quantity + en.",s:"J'{1} ai acheté deux. (of the books)",a:"en"},
        {type:"mc",q:"'Elle a besoin de vacances.' -> 'Elle ___ a besoin.'",opts:["Y","En","Les","La"],ans:"En",hint:"Avoir besoin DE + noun = de expression. Which pronoun?"},
        {type:"fb",opts:["en","y","les","le"],hint:"How many do you want? Partitive/quantity = en.",s:"Tu {1} veux combien? (of the apples)",a:"en"},
        {type:"match",pairs:[{trg:"du pain -> en",src:"some (partitive)"},{trg:"trois livres -> en...trois",src:"quantity"},{trg:"de l'eau -> en",src:"some (partitive)"},{trg:"besoin de repos -> en",src:"de expression"}]},
        {type:"mc",q:"'J'ai ___ soeurs.' -> 'J'en ai ___.' When en replaces the noun, what stays?",opts:["Elles","Les","Deux","Leur"],ans:"Deux",hint:"The noun is replaced by en, but the quantity word stays in the sentence."},
        {type:"fb",opts:["en","y","le","la"],hint:"There isn't any more. Il n'y en a plus = there is none left.",s:"Il n'{1} a plus. (of milk)",a:"en"},
        {type:"mc",q:"When do you keep the number with en?",opts:["Never","Only in negatives","Only with one","Always when a number is specified"],ans:"Always when a number is specified",hint:"J'en ai trois. J'en veux deux. The ___ stays."},
        {type:"fb",opts:["en","y","le","la"],hint:"We talked about it yesterday. Parler de = en.",s:"Nous {1} avons parlé hier. (about the problem)",a:"en"},
        {type:"match",pairs:[{trg:"Tu veux du thé?",src:"Tu en veux?"},{trg:"J'ai cinq livres",src:"J'en ai cinq"},{trg:"Elle parle de son voyage",src:"Elle en parle"},{trg:"Il y a des pommes",src:"Il y en a"}]},
        {type:"mc",q:"In the negative: 'Je n'___ veux pas.' (of cake)",opts:["En","Y","Le","La"],ans:"En",hint:"Ne + en + verb + pas. Same placement as other pronouns."},
        {type:"fb",opts:["en","y","le","la"],hint:"I'm coming from there! Venir de = en for places.",s:"J'{1} viens! (from there / from that place)",a:"en"},
        {type:"mc",q:"Y vs en: Y replaces ___, en replaces ___.",opts:["de + thing, à + place","à + place/thing, de + thing/quantity","person, place","place, person"],ans:"à + place/thing, de + thing/quantity",hint:"Y = à, en = de. That's the core distinction."},
        {type:"fb",opts:["en","y","le","la"],hint:"Do you have a lot of it? Quantity expression = en.",s:"Vous {1} avez beaucoup? (of money)",a:"en"}
  ]},
  {id:"fre13l5",title:"La place des pronoms",icon:"📐",xp:15,board:true,steps:[
        {type:"intro",title:"Where do pronouns go?",desc:"Pronoun placement changes in different sentence structures: present, passé composé, negative, imperative, and infinitive constructions. Master the placement rules.",goals:["Place pronouns correctly in all tenses","Handle negation with pronouns","Place pronouns with infinitives"]},
        {type:"tip",title:"Placement rules",text:"1. PRESENT: before conjugated verb\nJe le vois. Je lui parle.\n\n2. PASSÉ COMPOSÉ: before auxiliary\nJe l'ai vu. Je lui ai parlé.\n\n3. NEGATIVE: ne + pronoun + verb + pas\nJe ne le vois pas.\n\n4. INFINITIVE: before the infinitive\nJe vais le voir. (not: Je le vais voir.)\nJe peux lui parler.\n\n5. IMPERATIVE (affirmative): after verb\nRegarde-le! Parle-lui!\nIMPERATIVE (negative): before verb\nNe le regarde pas!"},
        {type:"teach",trg:"Je vais le faire.",src:"I'm going to do it.",pos:"verb",gender:null,phonetic:"zhuh vay luh FAIR",note:"With infinitive: pronoun before infinitive.\nJe vais + le + faire.\nNOT: Je le vais faire.",example:"A: Tu peux laver la vaisselle?\nB: Oui, je vais le faire après le dîner.\nA: Promis?",exampleSrc:"A: Can you wash the dishes?\nB: Yes, I'm going to do it after dinner.\nA: Promise?",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Donne-le-moi!",src:"Give it to me!",pos:"verb",gender:null,phonetic:"dohn luh MWAH",note:"Affirmative imperative: verb + pronouns.\nWith hyphens: Donne-le-moi.\nOrder: COD before COI after verb.",example:"A: C'est mon livre!\nB: Non, c'est le mien!\nA: Donne-le-moi!",exampleSrc:"A: It's my book!\nB: No, it's mine!\nA: Give it to me!",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"'Je peux ___ parler.' (to her) Where does lui go?",opts:["Before parler","Before peux","After parler","Before je"],ans:"Before parler",hint:"With two verbs, the pronoun goes ___ the one it relates to."},
        {type:"fb",opts:["le","la","les","lui"],hint:"She's going to buy it. Before the infinitive.",s:"Elle va {1} acheter. (it, masc.)",a:"le"},
        {type:"mc",q:"Negative: 'Je ___ vois ___.' (ne...pas, him)",opts:["le ne / pas","ne le / pas","ne / le pas","ne / pas le"],ans:"ne le / pas",hint:"The pronoun slots between the two negative elements, just before the verb."},
        {type:"fb",opts:["la","le","les","lui"],hint:"I don't understand her. Ne + pronoun + verb + pas.",s:"Je ne {1} comprends pas. (her)",a:"la"},
        {type:"match",pairs:[
          {trg:"Je le vois",src:"present: before verb"},
          {trg:"Je l'ai vu",src:"PC: before auxiliary"},
          {trg:"Je vais le voir",src:"infinitive: before infinitive"},
          {trg:"Regarde-le!",src:"imperative: after verb"}
        ]},
        {type:"mc",q:"Passé composé: 'Je ___ vu hier.' (them, masc.)",opts:["Les avais","Ai les","Les ai","Avais les"],ans:"Les ai",hint:"In PC, the pronoun goes before the auxiliary."},
        {type:"fb",opts:["leur","les","lui","la"],hint:"We're going to call them. Téléphoner à = indirect.",s:"Nous allons {1} téléphoner. (to them)",a:"leur"},
        {type:"mc",q:"Negative imperative: 'Ne ___ regarde ___!' (him)",opts:["le regarde / pas","pas / le","regarde le / pas","le / pas"],ans:"le / pas",hint:"Negative imperative = same as regular negative: before verb."},
        {type:"fb",opts:["me","moi","lui","te"],hint:"Don't talk to me about that! Negative imperative: pronoun before verb.",s:"Ne {1} parle pas de ça! (to me)",a:"me"},
        {type:"match",pairs:[
          {trg:"Parle-lui!",src:"Talk to him/her! (affirm.)"},
          {trg:"Ne lui parle pas!",src:"Don't talk to him/her!"},
          {trg:"Donne-les!",src:"Give them! (affirm.)"},
          {trg:"Ne les donne pas!",src:"Don't give them!"}
        ]},
        {type:"mc",q:"'Aide-___!' (me, affirmative imperative)",opts:["Moi","Me","Je","Mon"],ans:"Moi",hint:"After affirmative imperative, the unstressed pronoun shifts to its stressed form."},
        {type:"fb",opts:["m'","me","moi","mon"],hint:"Can you help me? Before infinitive starting with vowel.",s:"Tu peux {1} aider? (me)",a:"m'"},
        {type:"mc",q:"Which is correct?",opts:["Je le peux faire","Je peux le faire","Le je peux faire","Je peux faire le"],ans:"Je peux le faire",hint:"Pronoun goes directly before the infinitive it belongs to."},
        {type:"fb",opts:["l'","la","le","les"],hint:"Don't forget it! Before vowel, la becomes l'.",s:"Ne {1} oublie pas! (it, fem.)",a:"l'"}
  ]},
  {id:"fre13l6",title:"Les doubles pronoms",icon:"🔗",xp:15,board:true,steps:[
        {type:"intro",title:"Two pronouns together",desc:"Sometimes you need TWO pronouns in one sentence. French has a strict order for combining them. This is one of the trickiest parts of French grammar!",goals:["Learn the double pronoun order","Combine COD + COI","Use y and en with other pronouns"]},
        {type:"tip",title:"Double pronoun order",text:"When two pronouns appear together, they follow this order:\n\nme/te/se/nous/vous + le/la/les + lui/leur + y + en\n\n1 -> 2 -> 3 -> 4 -> 5\n\nExamples:\nIl me le donne. (He gives it to me.)\nJe le lui ai dit. (I told it to him.)\nIl y en a. (There is some.)\n\nNote: me/te/nous/vous BEFORE le/la/les\nBut le/la/les BEFORE lui/leur\nY and en always come last."},
        {type:"teach",trg:"Il me le donne.",src:"He gives it to me.",pos:"verb",gender:null,phonetic:"eel muh luh DOHN",note:"Two pronouns: me (to me) + le (it).\nOrder: me before le.\nBoth before the verb.",example:"A: Qui a le livre?\nB: Pierre. Il me le donne demain.\nA: D'accord!",exampleSrc:"A: Who has the book?\nB: Pierre. He's giving it to me tomorrow.\nA: OK!",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Je le lui ai dit.",src:"I told it to him/her.",pos:"verb",gender:null,phonetic:"zhuh luh lwee ay DEE",note:"Two pronouns: le (it) + lui (to him).\nOrder: le before lui.\nIn PC: both before the auxiliary.",example:"A: Tu as dit la vérité à Marc?\nB: Oui, je le lui ai dit hier.\nA: Comment il a réagi?",exampleSrc:"A: Did you tell Marc the truth?\nB: Yes, I told it to him yesterday.\nA: How did he react?",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"'Il donne le livre à moi.' With pronouns: 'Il ___ donne.'",opts:["me le","le me","me la","la me"],ans:"me le",hint:"Me/te/nous/vous come BEFORE le/la/les."},
        {type:"fb",opts:["nous","l'","lui","la"],hint:"She explained it to us. First person plural COI + elided COD.",s:"Elle {1} ___ a expliqué. (it to us, fem.)",a:["nous","l'"]},
        {type:"mc",q:"'Je donne les clés à Pierre.' -> 'Je ___ donne.' Two pronouns: which order?",opts:["lui les","les lui","le lui","lui le"],ans:"les lui",hint:"Direct object pronouns always precede indirect object pronouns in this order."},
        {type:"fb",opts:["le","leur","lui","les"],hint:"Did you show it to them? COD before COI (plural indirect).",s:"Tu {1} ___ as montré? (it to them, masc.)",a:["le","leur"]},
        {type:"match",pairs:[{trg:"me le",src:"it to me"},{trg:"te la",src:"it (f.) to you"},{trg:"le lui",src:"it to him/her"},{trg:"les leur",src:"them to them"}]},
        {type:"mc",q:"'Il y en a.' How many pronouns are there?",opts:["One","Three","Two","None"],ans:"Two",hint:"Il y en a contains both a place pronoun and a quantity pronoun."},
        {type:"fb",opts:["y","en","le","la"],hint:"There are many of them. Y before en.",s:"Il {1} ___ a beaucoup. (there / of them)",a:["y","en"]},
        {type:"mc",q:"In the double pronoun order, which group comes FIRST?",opts:["le/la/les","lui/leur","y/en","me/te/se/nous/vous"],ans:"me/te/se/nous/vous",hint:"Personal pronouns (me, te, etc.) go before object pronouns."},
        {type:"fb",opts:["te","le","lui","la"],hint:"I'm sending it to you tomorrow. Te before le.",s:"Je {1} ___ envoie demain. (it to you, masc.)",a:["te","le"]},
        {type:"match",pairs:[{trg:"1: me/te/se/nous/vous",src:"first position"},{trg:"2: le/la/les",src:"second position"},{trg:"3: lui/leur",src:"third position"},{trg:"4: y, 5: en",src:"last positions"}]},
        {type:"mc",q:"'Elle me les a donnés.' Identify the pronouns:",opts:["me = COI (to me), les = COD (them)","me = COD, les = COI","Both COD","Both COI"],ans:"me = COI (to me), les = COD (them)",hint:"She gave ___ (___) TO ME (___)."},
        {type:"fb",opts:["le","lui","la","leur"],hint:"Don't give it to him! Negative: ne + pronouns + verb + pas.",s:"Ne {1} ___ donne pas! (it to him, masc.)",a:["le","lui"]},
        {type:"mc",q:"Double pronouns are placed:",opts:["Both after the verb","Both before the conjugated verb","One before, one after","It varies"],ans:"Both before the conjugated verb",hint:"All pronouns cluster ___ the ___ ___ (or infinitive)."},
        {type:"fb",opts:["me","la","lui","le"],hint:"Can you lend it to me? Me before la, both before infinitive.",s:"Tu peux {1} ___ prêter? (it to me, fem.)",a:["me","la"]}
  ]},
  {id:"fre13l7",title:"En situation",icon:"🎬",xp:15,board:true,steps:[
        {type:"intro",title:"Pronouns in real life",desc:"Practice using all the pronouns you've learned in realistic everyday situations: at a restaurant, shopping, with friends, at work.",goals:["Apply pronouns naturally in context","Switch between COD, COI, y, and en","Build fluency with pronoun placement"]},
        {type:"teach",trg:"Je m'en occupe.",src:"I'll take care of it.",pos:"verb",gender:null,phonetic:"zhuh mahn oh-KEWP",note:"S'occuper de = to take care of.\nEn replaces 'de + the thing'.\nVery common in daily French.",example:"A: Qui va réserver le restaurant?\nB: Je m'en occupe!\nA: Merci, c'est gentil.",exampleSrc:"A: Who's going to book the restaurant?\nB: I'll take care of it!\nA: Thanks, that's kind.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Ça te dit?",src:"Does that appeal to you? / Sound good?",pos:"intj",gender:null,phonetic:"sah tuh DEE",note:"Dire à quelqu'un = informal expression.\nTe = to you (COI).\nResponse: Ça me dit = sounds good to me.",example:"A: On va au cinéma ce soir? Ça te dit?\nB: Oui, ça me dit bien!\nA: Super, on y va à 20 heures.",exampleSrc:"A: Shall we go to the cinema tonight? Sound good?\nB: Yes, sounds good to me!\nA: Great, let's go at 8 PM.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"mc",q:"A partitive noun (du sucre) is replaced by which pronoun in 'Oui, j'___ veux'?",opts:["En","Y","Le","La"],ans:"En",hint:"Partitive quantities (du, de la, des) are substituted by this specific pronoun."},
        {type:"fb",opts:["nous","les","leur","en"],hint:"The waiter brings us the menu. Apporter à = indirect.",s:"Le serveur {1} apporte le menu. (to us)",a:"nous"},
        {type:"mc",q:"Shopping: 'Vous avez cette robe en bleu?' -> 'Je vais ___.'",opts:["Y regarder","La regarder","Le regarder","En regarder"],ans:"La regarder",hint:"Cette robe (feminine) = direct object. Before the infinitive."},
        {type:"fb",opts:["en","y","les","le"],hint:"I bought three (of them). Quantity = en + number.",s:"J'{1} ai acheté trois. (of the croissants)",a:"en"},
        {type:"match",pairs:[{trg:"Tu en veux?",src:"Do you want some?"},{trg:"Je m'en occupe",src:"I'll handle it"},{trg:"On y va?",src:"Shall we go?"},{trg:"Ça te dit?",src:"Sound good?"}]},
        {type:"mc",q:"Friend: 'Tu penses à tes vacances?' -> 'Oui, j'___ pense tout le temps!'",opts:["Le","En","Y","La"],ans:"Y",hint:"Penser à + thing = which pronoun?"},
        {type:"fb",opts:["lui","le","leur","en"],hint:"Did you talk to the boss? Parler à + person = indirect.",s:"Tu {1} as parlé? (to the boss)",a:"lui"},
        {type:"mc",q:"'Il y a du lait?' -> 'Non, il n'___ a plus.'",opts:["En","En y","Y","Y en"],ans:"Y en",hint:"Il y a: y stays, en replaces du lait."},
        {type:"fb",opts:["les","leur","le","en"],hint:"I don't know them. Connaître = direct object.",s:"Je ne {1} connais pas. (them, the neighbors)",a:"les"},
        {type:"match",pairs:[{trg:"Je lui écris",src:"I write to him/her"},{trg:"J'y vais",src:"I'm going there"},{trg:"J'en veux",src:"I want some"},{trg:"Je les vois",src:"I see them"}]},
        {type:"mc",q:"At work: 'Tu as envoyé le rapport au directeur?' -> 'Oui, je ___ ai envoyé.'",opts:["Le lui","Lui le","Le la","La lui"],ans:"Le lui",hint:"Le (the report, COD) + ___ (to the director, COI)."},
        {type:"fb",opts:["te","toi","tu","vous"],hint:"She's going to call you tonight. Téléphoner à = indirect.",s:"Elle va {1} téléphoner ce soir. (to you, informal)",a:"te"},
        {type:"mc",q:"Which is the most natural response to 'Tu veux du gâteau?'",opts:["Oui, je le veux","Oui, j'en veux bien","Oui, je veux","Oui, j'y veux"],ans:"Oui, j'en veux bien",hint:"Du gâteau (partitive) needs the pronoun that replaces de."},
        {type:"fb",opts:["moi","me","mon","ma"],hint:"Affirmative imperative shifts the first-person pronoun to its stressed form.",s:"Dis-{1} la vérité! (to me, affirmative imperative)",a:"moi"},
        {type:"mc",q:"Summary: mastering pronouns means replacing nouns to make French sound:",opts:["Longer and more formal","More complicated","Shorter and more natural","More English-like"],ans:"Shorter and more natural",hint:"Pronouns avoid repetition. That's their entire purpose."}
  ]},
  {id:"fre13l8",title:"Révision des pronoms",icon:"🏆",xp:15,board:true,steps:[
        {type:"intro",title:"Pronoun mastery review",desc:"Comprehensive review of all pronoun types: COD (le/la/les), COI (lui/leur), Y, EN, placement rules, and double pronouns. Test yourself!",goals:["Distinguish all pronoun types","Place pronouns in any sentence structure","Handle tricky combinations"]},
        {type:"tip",title:"Quick reference",text:"COD: le, la, les (+ me, te, nous, vous)\nReplace: direct object (no preposition)\n\nCOI: lui, leur (+ me, te, nous, vous)\nReplace: à + person\n\nY: replace à + place/thing (not person)\n\nEN: replace de + thing, partitive, quantity\n\nOrder: me/te/se/nous/vous > le/la/les > lui/leur > y > en\n\nPlacement: before conjugated verb (or infinitive)"},
        {type:"mc",q:"A famous feminine monument is the direct object. 'Oui, je ___ vois!' Which pronoun?",opts:["La","Le","Les","Y"],ans:"La",hint:"The pronoun must match the gender and number of the substituted noun."},
        {type:"fb",opts:["lui","la","leur","en"],hint:"He gave her flowers. Donner à = indirect object.",s:"Il {1} a donné des fleurs. (to her)",a:"lui"},
        {type:"mc",q:"'Tu vas à Paris?' -> 'Oui, j'___ vais demain.'",opts:["En","Y","Le","La"],ans:"Y",hint:"À + place = which pronoun?"},
        {type:"fb",opts:["en","y","les","le"],hint:"I ate three of them. Quantity = en + number.",s:"J'{1} ai mangé trois. (of the macarons)",a:"en"},
        {type:"match",pairs:[{trg:"COD: le/la/les",src:"direct object"},{trg:"COI: lui/leur",src:"à + person"},{trg:"Y",src:"à + place/thing"},{trg:"EN",src:"de + thing/quantity"}]},
        {type:"mc",q:"'Je ___ ___ ai montré.' (it to her, the photo)",opts:["La leur","Lui la","La lui","Le lui"],ans:"La lui",hint:"La (the photo, COD) before ___ (to her, COI)."},
        {type:"fb",opts:["le","la","les","lui"],hint:"Don't touch it! Negative: ne + pronoun + verb + pas.",s:"Ne {1} touche pas! (it, masc.)",a:"le"},
        {type:"mc",q:"With infinitive: 'Je veux ___ voir.' (them)",opts:["Leur les","Leur","Les les","Les"],ans:"Les",hint:"Pronoun goes before the infinitive. I want to see them."},
        {type:"fb",opts:["y","en","le","la"],hint:"We think about it often. Penser à + thing = which pronoun?",s:"Nous {1} pensons souvent. (about our trip)",a:"y"},
        {type:"match",pairs:[{trg:"Regarde-le!",src:"Look at it! (imperative)"},{trg:"Ne le regarde pas!",src:"Don't look at it!"},{trg:"Je vais le voir",src:"I'm going to see him"},{trg:"Je l'ai vu",src:"I saw him (PC)"}]},
        {type:"mc",q:"'Tu as besoin de repos?' -> 'Oui, j'___ ai besoin.'",opts:["En","Y","Le","La"],ans:"En",hint:"Avoir besoin DE = de expression. Which pronoun?"},
        {type:"fb",opts:["nous","le","lui","la"],hint:"She's going to send it to us. First person plural before masc. COD.",s:"Elle va {1} ___ envoyer. (it to us, the email)",a:["nous","le"]},
        {type:"mc",q:"'Il y en a beaucoup.' This sentence has ___ pronoun(s).",opts:["One","Two","Three","None"],ans:"Two",hint:"Il y en a beaucoup: count both the place pronoun and the quantity pronoun."},
        {type:"fb",opts:["lui","le","il","leur"],hint:"Talk to him! Affirmative imperative: pronoun after verb.",s:"Parle-{1}! (to him, affirmative imperative)",a:"lui"},
        {type:"mc",q:"The hardest part of French pronouns is:",opts:["Knowing which pronoun to use","Knowing where to place them","Both choosing and placing","None of the above"],ans:"Both choosing and placing",hint:"You must pick the right pronoun AND put it in the right spot."},
        {type:"fb",opts:["leur","les","lui","en"],hint:"I didn't tell them. Dire à = indirect. Negative PC placement.",s:"Je ne {1} ai pas dit. (to them)",a:"leur"},
        {type:"mc",q:"You've mastered French pronouns! They make speech:",opts:["Longer","More formal only","More confusing","Shorter and more fluid"],ans:"Shorter and more fluid",hint:"No more repeating nouns. That's the power of pronouns!"}
  ]},
  {id:"fre13l8b",title:"La Santé",icon:"🏥",xp:15,board:true,steps:[
        {type:"intro",title:"La Santé",desc:"Learn essential health vocabulary and how to describe symptoms in French.",goals:["Learn 12 health-related words","Use avoir mal à + body part","Describe symptoms at the doctor"]},
        {type:"teach",trg:"malade",src:"sick/ill",pos:"adj",gender:null,phonetic:"ma-LAD",note:"malade: adjective, same m/f form.\nêtre malade: to be sick.",example:"A: Tu es malade ?\nB: Oui, je suis très malade.\nA: Depuis quand ?\nB: Depuis hier soir.",exampleSrc:"A: Are you sick?\nB: Yes, I am very sick.\nA: Since when?\nB: Since last night.",funFact:"French adjectives agree in gender and number with their noun. Most add -e for feminine."},
        {type:"teach",trg:"la fièvre",src:"the fever",pos:"noun",gender:"f",phonetic:"la FYEV-ruh",note:"la fièvre: feminine noun.\navoir de la fièvre: to have a fever.",example:"A: Tu as de la fièvre ?\nB: Oui, j'ai 39 degrés.\nA: C'est beaucoup !\nB: Je dois rester au lit.",exampleSrc:"A: Do you have a fever?\nB: Yes, I have 39 degrees.\nA: That is a lot!\nB: I must stay in bed.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"la toux",src:"the cough",pos:"verb",gender:null,phonetic:"la TOO",note:"la toux: feminine noun.\nVerb: tousser (to cough).",example:"A: Tu as une toux ?\nB: Oui, je tousse beaucoup.\nA: Prends du sirop.\nB: Bonne idée, merci.",exampleSrc:"A: Do you have a cough?\nB: Yes, I cough a lot.\nA: Take some syrup.\nB: Good idea, thanks.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"le rhume",src:"the cold",pos:"noun",gender:"m",phonetic:"luh ROOM",note:"le rhume: masculine noun.\navoir un rhume / être enrhumé.",example:"A: J'ai un gros rhume.\nB: Tu as le nez qui coule ?\nA: Oui, et j'éternue tout le temps.\nB: Reste au chaud.",exampleSrc:"A: I have a bad cold.\nB: Do you have a runny nose?\nA: Yes, and I sneeze all the time.\nB: Stay warm.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le mal de tête",src:"the headache",pos:"noun",gender:"m",phonetic:"luh MAL duh TET",note:"avoir mal à la tête: to have a headache.\navoir mal à + article + body part.",example:"A: Tu as mal à la tête ?\nB: Oui, un terrible mal de tête.\nA: Prends un médicament.\nB: Oui, j'ai besoin d'aspirine.",exampleSrc:"A: Do you have a headache?\nB: Yes, a terrible headache.\nA: Take some medicine.\nB: Yes, I need aspirin.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le mal de ventre",src:"the stomachache",pos:"noun",gender:"m",phonetic:"luh MAL duh VON-truh",note:"avoir mal au ventre: to have a stomachache.\nau = à + le (contraction).",example:"A: Qu'est-ce qui ne va pas ?\nB: J'ai mal au ventre.\nA: Tu as mangé quelque chose de mauvais ?\nB: Peut-être le poisson d'hier.",exampleSrc:"A: What is wrong?\nB: I have a stomachache.\nA: Did you eat something bad?\nB: Maybe the fish from yesterday.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"le médicament",src:"the medicine/medication",pos:"noun",gender:"m",phonetic:"luh may-dee-ka-MON",note:"le médicament: masculine noun.\nPlural: les médicaments.",example:"A: Tu prends des médicaments ?\nB: Oui, trois fois par jour.\nA: C'est le médecin qui les a prescrits ?\nB: Oui, avec une ordonnance.",exampleSrc:"A: Do you take medication?\nB: Yes, three times a day.\nA: Did the doctor prescribe them?\nB: Yes, with a prescription.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"l'hôpital",src:"the hospital (m)",pos:"noun",gender:"m",phonetic:"lo-pee-TAL",note:"l'hôpital: masculine noun.\nPlural: les hôpitaux.",example:"A: Il faut aller à l'hôpital.\nB: Pourquoi ? C'est grave ?\nA: Non, juste pour un examen.\nB: D'accord, allons-y.",exampleSrc:"A: We need to go to the hospital.\nB: Why? Is it serious?\nA: No, just for a check-up.\nB: Okay, let's go.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"la pharmacie",src:"the pharmacy",pos:"noun",gender:"f",phonetic:"la far-ma-SEE",note:"la pharmacie: feminine noun.\nNot to confuse with le pharmacien (pharmacist).",example:"A: Je dois aller à la pharmacie.\nB: Tu as besoin de quoi ?\nA: De sirop pour la toux.\nB: Il y en a une près d'ici.",exampleSrc:"A: I need to go to the pharmacy.\nB: What do you need?\nA: Cough syrup.\nB: There is one nearby.",funFact:"Cognate with English 'pharmacy'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"l'ordonnance",src:"the prescription (f)",pos:"noun",gender:"f",phonetic:"lor-do-NONS",note:"l'ordonnance: feminine noun.\nRequired for many medicines in France.",example:"A: Tu as une ordonnance ?\nB: Oui, le médecin m'en a donné une.\nA: Montre-la au pharmacien.\nB: D'accord.",exampleSrc:"A: Do you have a prescription?\nB: Yes, the doctor gave me one.\nA: Show it to the pharmacist.\nB: Okay.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"la piqûre",src:"the injection/shot",pos:"noun",gender:"f",phonetic:"la pee-KOOR",note:"la piqûre: feminine noun.\nAlso: insect bite (piqûre d'insecte).",example:"A: Tu as peur des piqûres ?\nB: Un peu, oui.\nA: L'infirmière est très douce.\nB: D'accord, je suis prêt.",exampleSrc:"A: Are you afraid of injections?\nB: A little, yes.\nA: The nurse is very gentle.\nB: Okay, I am ready.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"l'allergie",src:"the allergy (f)",pos:"noun",gender:"f",phonetic:"la-lehr-ZHEE",note:"l'allergie: feminine noun.\nêtre allergique à: to be allergic to.",example:"A: Tu as des allergies ?\nB: Oui, je suis allergique au pollen.\nA: C'est difficile au printemps ?\nB: Oui, j'éternue beaucoup.",exampleSrc:"A: Do you have allergies?\nB: Yes, I am allergic to pollen.\nA: Is it difficult in spring?\nB: Yes, I sneeze a lot.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"tip",title:"Avoir mal à + le corps",deepDive:{
          title:"More health expressions",
          text:"Other useful health phrases:\nJe ne me sens pas bien. (I don't feel well.)\nJ'ai besoin de voir un médecin. (I need to see a doctor.)\nOù est la pharmacie la plus proche ? (Where is the nearest pharmacy?)\nC'est urgent. (It's urgent.)"
        },text:"To express pain in French, use:\navoir mal à + article + body part.\nJ'ai mal à la tête. (headache)\nJ'ai mal au ventre. (stomachache)\nJ'ai mal aux dents. (toothache)\nNote contractions: à + le = au, à + les = aux."},
        {type:"mc",q:"How do you say 'I have a headache' in French?",opts:["J'ai mal à la tête","J'ai mal au dos","J'ai mal au ventre","J'ai mal aux pieds"],ans:"J'ai mal à la tête",hint:"The head is la ___, and the structure uses à + la."},
        {type:"mc",q:"What does 'l'ordonnance' mean?",opts:["the medicine","the prescription","the pharmacy","the hospital"],ans:"the prescription",hint:"A doctor gives you this paper to get your medicine."},
        {type:"fb",opts:["malade","fatigué","content","triste"],hint:"This adjective describes someone who is unwell or ill.",s:"Je suis {1}, j'ai de la fièvre et je tousse.",a:["malade"]},
        {type:"fb",opts:["pharmacie","boulangerie","bibliothèque","gare"],hint:"A store specifically dedicated to selling medicines.",s:"Il faut aller à la {1} pour acheter des médicaments.",a:["pharmacie"]},
        {type:"match",pairs:[{trg:"la fièvre",src:"the fever"},{trg:"la toux",src:"the cough"},{trg:"le rhume",src:"the cold"},{trg:"le médicament",src:"the medicine"},{trg:"l'allergie",src:"the allergy"},{trg:"la piqûre",src:"the injection/shot"}]}
  ]},
  {id:"fre13l8c",title:"Prendre un rendez-vous",icon:"📅",xp:15,board:true,steps:[
        {type:"intro",title:"Prendre un rendez-vous",desc:"Learn to make, confirm, and reschedule appointments in French. This is a core real-life skill tested on DELF A2 and needed for doctors, dentists, and restaurants.",goals:["Make an appointment by phone","Confirm or cancel an appointment","Reschedule a meeting","Use polite request forms"]},
        {type:"teach",trg:"le rendez-vous",src:"the appointment",pos:"noun",gender:"m",note:"Masculine noun. Literally 'render yourself' (meet up here).\nUsed for medical appointments, meetings, and dates.\nPrendre un rendez-vous = to make an appointment.",example:"A: Je voudrais prendre un rendez-vous.\nB: Oui, c'est pour quand ?\nA: Pour jeudi, si possible.\nB: Jeudi à 14h, c'est parfait.",exampleSrc:"A: I would like to make an appointment.\nB: Yes, when is it for?\nA: For Thursday, if possible.\nB: Thursday at 2pm, perfect.",funFact:"'Rendez-vous' entered English unchanged and is used worldwide in medicine and diplomacy. It literally means 'present yourselves' in French."},
        {type:"teach",trg:"prendre un rendez-vous",src:"to make an appointment",pos:"verb",gender:null,note:"Verb phrase. Prendre (irregular) = to take/make.\nPrendre is used for many appointments and choices.",example:"A: Je dois prendre un rendez-vous chez le médecin.\nB: Tu peux appeler ce matin.\nA: Oui, je vais appeler tout de suite.\nB: Dis-leur que c'est urgent.",exampleSrc:"A: I need to make an appointment with the doctor.\nB: You can call this morning.\nA: Yes, I'll call right away.\nB: Tell them it's urgent.",funFact:"French uses 'prendre' (take) for making appointments, just as English uses 'make'. These are both arbitrary verb choices from each language's history."},
        {type:"teach",trg:"confirmer",src:"to confirm",pos:"verb",gender:null,note:"Regular -er verb. Je confirme, vous confirmez.\nUsed to confirm appointments, reservations, and plans.",example:"A: Je vous appelle pour confirmer mon rendez-vous.\nB: Oui, c'est bien noté pour lundi à 10h.\nA: Merci beaucoup.\nB: À lundi alors.",exampleSrc:"A: I'm calling to confirm my appointment.\nB: Yes, it is noted for Monday at 10am.\nA: Thank you very much.\nB: See you Monday then.",funFact:"French has had major influence on English since 1066. 'Confirm' comes from French 'confirmer', from Latin 'confirmare'."},
        {type:"teach",trg:"annuler",src:"to cancel",pos:"verb",gender:null,note:"Regular -er verb. J'annule, vous annulez.\nNote the silent 'nn': pronounced 'ah-nu-LAY'.",example:"A: Je dois annuler mon rendez-vous de demain.\nB: Pas de problème. Vous voulez reporter ?\nA: Oui, la semaine prochaine, si possible.\nB: Mercredi à 16h, ça vous convient ?",exampleSrc:"A: I need to cancel my appointment tomorrow.\nB: No problem. Would you like to reschedule?\nA: Yes, next week if possible.\nB: Wednesday at 4pm, does that suit you?",funFact:"From Latin 'annullare' (to make null). The double-n is preserved in writing but both n's merge in speech."},
        {type:"teach",trg:"reporter",src:"to reschedule / postpone",pos:"verb",gender:null,note:"Regular -er verb. Je reporte, vous reportez.\nReporter = to move to a later time.\nNot the same as English 'to report'!",example:"A: Puis-je reporter mon rendez-vous ?\nB: Bien sûr. Quelle date vous convient ?\nA: Vendredi matin, si c'est possible.\nB: Vendredi à 9h, c'est possible.",exampleSrc:"A: Can I reschedule my appointment?\nB: Of course. What date suits you?\nA: Friday morning if possible.\nB: Friday at 9am, that works.",funFact:"A false cognate. 'Reporter' in French means to postpone or reschedule. In English 'to report' has a completely different meaning."},
        {type:"teach",trg:"Quel jour vous convient ?",src:"What day suits you?",pos:"intj",gender:null,note:"Formal phone phrasing.\nConvenir à = to suit, to be convenient for.\nMore polite than: 'Quel jour est bon pour vous ?'",example:"A: Quel jour vous convient pour le rendez-vous ?\nB: Mardi ou jeudi, si possible.\nA: Mardi à 11h, c'est bon ?\nB: Oui, c'est parfait, merci.",exampleSrc:"A: What day suits you for the appointment?\nB: Tuesday or Thursday, if possible.\nA: Tuesday at 11am, is that good?\nB: Yes, that's perfect, thank you.",funFact:"The verb 'convenir' shares roots with English 'convenient'. It literally means 'to come together' (Latin 'convenire')."},
        {type:"teach",trg:"Je voudrais prendre rendez-vous pour...",src:"I would like to make an appointment for...",pos:"intj",gender:null,note:"Standard telephone phrase for making appointments.\nVoudrais = conditional of vouloir (polite).\nComplete with: lundi / chez le dentiste / etc.",example:"A: Bonjour, je voudrais prendre rendez-vous pour une consultation.\nB: C'est noté. Vous préférez le matin ou l'après-midi ?\nA: Le matin, de préférence.\nB: Jeudi à 9h30, ça vous va ?",exampleSrc:"A: Hello, I would like to make an appointment for a consultation.\nB: Noted. Do you prefer morning or afternoon?\nA: Morning, preferably.\nB: Thursday at 9:30am, does that work for you?",funFact:"Using the conditional 'voudrais' instead of 'veux' is not just polite, it is essential on the phone in France. Bare 'je veux' can sound rude."},
        {type:"teach",trg:"Est-ce que vous avez quelque chose plus tôt ?",src:"Do you have anything earlier?",pos:"intj",gender:null,note:"Practical negotiation phrase for appointments.\nQuelque chose = something. Plus tôt = earlier.\nCan also ask: 'plus tard' (later).",example:"A: Votre prochain disponible est dans trois semaines.\nB: Est-ce que vous avez quelque chose plus tôt ?\nA: Il y a une annulation pour vendredi.\nB: Oui, je prends vendredi, merci.",exampleSrc:"A: Your next available is in three weeks.\nB: Do you have anything earlier?\nA: There is a cancellation for Friday.\nB: Yes, I'll take Friday, thank you.",funFact:"Medical French uses formal 'vous'. Switching to 'tu' with a receptionist would sound very unusual and slightly rude."},
        {type:"tip",title:"Making appointments by phone",text:"Standard script for calling a doctor's office in French:\n\n1. Greeting:\n'Bonjour, je voudrais prendre un rendez-vous.'\n\n2. Provide your name:\n'C'est de la part de [name].'\n\n3. Indicate urgency or preference:\n'C'est urgent.' or 'Le matin de préférence.'\n\n4. Confirm details:\n'Donc c'est bien mardi à 14h, c'est ça ?'\n\nKey vocabulary:\nle rendez-vous = the appointment\nle cabinet médical = the doctor's office\ndisponible = available\nune annulation = a cancellation"},
        {type:"mc",q:"Which verb means 'to reschedule' an appointment in French?",opts:["reporter","prendre","annuler","confirmer"],ans:"reporter",hint:"Moving an appointment to a later time. Not the same as the English word that looks similar."},
        {type:"fb",opts:["prendre","donner","faire","mettre"],hint:"Je voudrais ___ un rendez-vous. The standard verb for 'making' an appointment.",s:"Je voudrais {1} un rendez-vous chez le médecin.",a:"prendre"},
        {type:"mc",q:"'Quel jour vous convient ?' is used to ask:",opts:["What day is the appointment?","What day suits you?","What day is the office open?","What day did you cancel?"],ans:"What day suits you?",hint:"Convenir à = to suit. This is the receptionist asking the patient."},
        {type:"match",pairs:[{trg:"prendre un rendez-vous",src:"to make an appointment"},{trg:"annuler",src:"to cancel"},{trg:"reporter",src:"to reschedule / postpone"},{trg:"confirmer",src:"to confirm"},{trg:"le rendez-vous",src:"the appointment"}]},
        {type:"fb",opts:["annuler","reporter","confirmer","prendre"],hint:"Moving it to another day, not deleting it completely.",s:"Je dois {1} mon rendez-vous. Puis-je avoir jeudi à la place ?",a:"reporter"}
  ]}
]};
